class Solution {
public:
    string reverseWords(string s) {
        int n = s.size();

        char prev = ' ';
        string myString(n, ' ');
        int index = n;

        for(int i = 0; i < n; i++){
            if(prev ==' ' && s[i] != ' '){
                int start = i;
                while(s[i] != ' ' && i < n){
                    i++;
                }
                string temp_str = s.substr(start, i-start);
                index -= temp_str.size();
                if(index -1 > 0){
                    temp_str = " " + temp_str;
                    index--;
                }
                myString.replace(index, temp_str.size(), temp_str);
            }
            prev = s[i];
        }

        int space_index = 0;
        while(myString[space_index] == ' ' && space_index < n){
            space_index++;
        }

        return myString.substr(space_index, n- space_index);
    }
};
